apt-get update && apt-get install -y python3 python3-pip rustc cargo
pip3 install pytest

mkdir -p /home/user

# Create template (1000 bp long)
python3 -c "print('ATGC' * 250)" > /home/user/template.txt

# Create primers
cat << 'EOF' > /home/user/primers.txt
ATGCATGCATGC

GCATGCATGC
EOF

# Create experimental dist
cat << 'EOF' > /home/user/experimental_dist.json
{
  "1000": 0.35,
  "999": 0.35,
  "998": 0.30
}
EOF

useradd -m -s /bin/bash user || true
chmod -R 777 /home/user